#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelBCEWithLogits {
public:
    __aicore__ inline KernelBCEWithLogits() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y, GM_ADDR loss,
                                uint32_t totalLength, uint32_t tileLength)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);
        lossGm_.SetGlobalBuffer((__gm__ float*)loss, 1);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(inQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 2, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0) return;

        // Single block processes all tiles sequentially
        float sum = 0.0f;
        uint32_t offset = 0;
        while (offset < totalLen_) {
            uint32_t len = totalLen_ - offset;
            if (len > tileLen_) len = tileLen_;

            // Copy in x and y
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::LocalTensor<float> yLocal = inQueueY_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[offset], len);
            AscendC::DataCopy(yLocal, yGm_[offset], len);

            // Compute element-wise loss and accumulate sum
            AscendC::LocalTensor<float> t1 = tmpQueue_.AllocTensor<float>();
            AscendC::LocalTensor<float> t2 = tmpQueue_.AllocTensor<float>();
            AscendC::LocalTensor<float> lossLocal = tmpQueue_.AllocTensor<float>();

            // loss = max(x,0) - x*y + log1p(exp(-abs(x)))
            AscendC::Abs(t1, xLocal, len);
            AscendC::Mul(t2, t1, -1.0f, len);
            AscendC::Exp(t1, t2, len);
            AscendC::Log1p(t1, t1, len);

            AscendC::Max(t2, xLocal, 0.0f, len);
            AscendC::Mul(lossLocal, xLocal, yLocal, len);
            AscendC::Sub(t2, t2, lossLocal, len);
            AscendC::Add(lossLocal, t2, t1, len);

            // Reduce within tile (vector sum)
            AscendC::ReduceSum(t1, lossLocal, len);
            // Extracting scalar from local tensor
            float tileSum = t1(0);
            sum += tileSum;

            tmpQueue_.FreeTensor(t1);
            tmpQueue_.FreeTensor(t2);
            tmpQueue_.FreeTensor(lossLocal);
            inQueueX_.FreeTensor(xLocal);
            inQueueY_.FreeTensor(yLocal);

            offset += len;
        }

        // Compute mean
        float mean = sum / static_cast<float>(totalLen_);
        // Write to output (scalar)
        lossGm_(0) = mean;
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 3> tmpQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;
    AscendC::GlobalTensor<float> lossGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
};

extern "C" __global__ __aicore__ void ca6k_00240_custom(GM_ADDR x, GM_ADDR y, GM_ADDR loss, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelBCEWithLogits op;
    op.Init(x, y, loss, tiling_data.totalLength, tiling_data.tileLength);
    op.Process();
}
